import {
  html,
  customElement,
  property,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbPropertyEditorUiElement } from "@umbraco-cms/backoffice/property-editor";
import { UmbLitElement } from "@umbraco-cms/backoffice/lit-element";
import FormsInputThemeElement from "../../components/input-theme/input-theme.element.js";

const elementName = "forms-theme-picker-property-editor";

@customElement(elementName)
export class FormsThemePickerPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  @property()
  value = "";

  #onChange(event: Event) {
    const target = event.target as FormsInputThemeElement;
    this.value = target.value;
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  render() {
    return html`<forms-input-theme
      @change=${this.#onChange}
      .value=${this.value}
      slot="editor"></forms-input-theme>`;
  }
}

export default FormsThemePickerPropertyUiElement;

declare global {
	interface HTMLElementTagNameMap {
		[elementName]: FormsThemePickerPropertyUiElement;
	}
}
